# ============================================================================
#  Sakum Lang - full specification, embedded as raw machine-level data.
#  Generated from the spec modules.  The program walks the
#  embedded binary-hash-addressable knowledge and prints it, then prints
#  the FNV-1a digest of the whole corpus (the "binary hash" of the spec).
#  LaTeX math symbols used in the spec map to Sakum keywords - see
#  docs/SYMBOL_MAP.md.
# ============================================================================

    .section .text
    .globl main
    .p2align 4
main:
    push %rbp
    mov %rsp, %rbp
    sub $32, %rsp
    mov $1, %rcx
    lea spec_blob(%rip), %rdx
    mov spec_len(%rip), %r8
    call write
    lea fmt(%rip), %rcx
    movl $0xC46A785B, %edx
    call printf
    xor %eax, %eax
    ret
