.ascii "b2c3d4e5f60718293a4b5c6d7e8fe3;\x0a\xe0\xa4\xb2\xe0\xa5\x87\xe0\xa4\x96(query(\"load Sakum AI C"
.ascii "ore\"));\x0a\xe0\xa4\xb2\xe0\xa5\x87\xe0\xa4\x96(heartbeat());\x0a\x0a# lifecycle (\xe0\xa4\x9c\xe0\xa5\x80\xe0\xa4\xb5\xe0\xa4\xa8\xe0\xa4\x9a\xe0\xa4\x95"
.ascii "\xe0\xa5\x8d\xe0\xa4\xb0)\x0a\xe0\xa4\xb8\xe0\xa5\x82\xe0\xa4\xa4\xe0\xa5\x8d\xe0\xa4\xb0 ai_lifecycle() {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 walk_dir = 1"
.ascii "        # bounded 3-level opendir$INODE64 / readdir$INODE64\x0a    "
.ascii "\xe0\xa4\x9a\xe0\xa4\xb0 maybe_load = 1      # _open$NOCANCEL + _fstat$INODE64 ver"
.ascii "ify + _read\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 ingest = 1          # #what hex + node na"
.ascii "me + query folded into W\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 forward = 1         # Vout ="
.ascii " W . Vin (8x8)\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 self_update = 1     # fopen ledger \"a\""
.ascii " + fprintf tick\x0a    \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4\xaa\xe0\xa4\xb8 walk_dir + maybe_load + ingest "
.ascii "+ forward + self_update\x0a}\x0a\x0a# ingestion: binary-hash imprint + co"
.ascii "ntent fold\x0a\xe0\xa4\xb8\xe0\xa5\x82\xe0\xa4\xa4\xe0\xa5\x8d\xe0\xa4\xb0 ingest_chunk(hex, name, query, chunk_"
.ascii "idx) {\x0a    # W[idx] = (W[idx] * 16 + digit) mod 9973   for each "
.ascii "hex digit\x0a    # fold_str: W[(base+i)%64] = (W[...]*31 + byte) mo"
.ascii "d 9973  for name & query\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 hash_window = chunk_idx\x0a    "
.ascii "\xe0\xa4\x9a\xe0\xa4\xb0 name_window = chunk_idx\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 query_window = chunk_i"
.ascii "dx + 32\x0a    \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4\xaa\xe0\xa4\xb8 hash_window + name_window + query_windo"
.ascii "w\x0a}\x0a\x0a# RAM-aware neuron scaling: +8 per chunk, cap 64\x0a\xe0\xa4\xb8\xe0\xa5\x82\xe0\xa4\xa4\xe0"
.ascii "\xa5\x8d\xe0\xa4\xb0 neurons_loaded(chunks) {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 n = chunks * 8\x0a    \xe0\xa4\xaf"
.ascii "\xe0\xa4\xa6\xe0\xa4\xbf (n > 64) { n = 64 }\x0a    \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4\xaa\xe0\xa4\xb8 n\x0a}\x0a\x0a# weights must "
.ascii "NOT be overwritten after ingestion\x0a\xe0\xa4\xb8\xe0\xa5\x82\xe0\xa4\xa4\xe0\xa5\x8d\xe0\xa4\xb0 load_weights("
.ascii "W_filled) {\x0a    # seeds only Vin; leaves W[] intact\x0a    \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4"
.ascii "\xaa\xe0\xa4\xb8 W_filled\x0a}\x0a\x0a\xe0\xa4\xaa\xe0\xa4\xb0\xe0\xa5\x80\xe0\xa4\x95\xe0\xa5\x8d\xe0\xa4\xb7\xe0\xa4\xbe {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 life = ai_li"
.ascii "fecycle()\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 n = neurons_loaded(85)\x0a    \xe0\xa4\xae\xe0\xa5\x81\xe0\xa4\xa6\xe0\xa5\x8d\xe0\xa4\xb0\xe0"
.ascii "\xa4\xa3 \"ai ok: lifecycle=\" life \" neurons=\" n\x0a}\x0a\x0a\x0a# spec_build.sakum"
.ascii " - Sakum Lang formal spec: build & run matrix (\xe0\xa4\xa8\xe0\xa4\xbf\xe0\xa4\xb0\xe0\xa5\x8d\xe0\xa4\xae\xe0\xa4"
.ascii "\xbe\xe0\xa4\xa3)\x0a# Sakum-language spelling of docs/ch_build.tex.\x0a# Every co"
.ascii "re assembles with gcc -arch x86_64 ... ; doctrine-compliant.\x0a\x0a\xe0\xa4"
.ascii "\xa8\xe0\xa4\xbe\xe0\xa4\xae node = \"Sakum Build Matrix\";\x0a\xe0\xa4\xa8\xe0\xa4\xbe\xe0\xa4\xae hash = #what 90a1"
.ascii "b2c3d4e5f60718293a4b5c6d7e909e;\x0a\xe0\xa4\xb2\xe0\xa5\x87\xe0\xa4\x96(query(\"load Sakum Buil"
