.ascii "\xe0\xa5\x8d\xe0\xa4\xb0 doctrine_do() {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 raw_machine = 1          # bac"
.ascii "k ends emit raw machine-level code\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 binary_hash = 1   "
.ascii "       # every construct addressable by #what\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 sutra_k"
.ascii "ey = 1            # creator-owned key, not SHA-derived\x0a    \xe0\xa4\x9a\xe0\xa4"
.ascii "\xb0 vektor_first = 1         # \xe0\xa4\xb5\xe0\xa5\x87\xe0\xa4\x95\xe0\xa5\x8d\xe0\xa4\x9f\xe0\xa4\xb0 is first-class\x0a "
.ascii "   \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4\xaa\xe0\xa4\xb8 raw_machine + binary_hash + sutra_key + vektor_f"
.ascii "irst\x0a}\x0a\x0a# \xc2\xa72 DON'T \xe2\x80\x94 hard constraints\x0a\xe0\xa4\xb8\xe0\xa5\x82\xe0\xa4\xa4\xe0\xa5\x8d\xe0\xa4\xb0 doctrin"
.ascii "e_dont() {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 no_host_runtime = 1      # do not depend o"
.ascii "n a foreign high-level runtime\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 no_erase_doctrine = 1 "
.ascii "   # do not let AI erase prior doctrine\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 no_single_isa"
.ascii " = 1        # back ends are pluggable\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 no_slow = 1    "
.ascii "          # do not make it slower than necessary\x0a    \xe0\xa4\xb5\xe0\xa4\xbe\xe0\xa4\xaa\xe0\xa4"
.ascii "\xb8 no_host_runtime + no_erase_doctrine + no_single_isa + no_slow\x0a"
.ascii "}\x0a\x0a\xe0\xa4\xaa\xe0\xa4\xb0\xe0\xa5\x80\xe0\xa4\x95\xe0\xa5\x8d\xe0\xa4\xb7\xe0\xa4\xbe {\x0a    \xe0\xa4\x9a\xe0\xa4\xb0 d = doctrine_do()\x0a    \xe0\xa4\x9a\xe0"
